// 閾堕緞涔愬敱 鈥?App shell & router

function App() {
  // Persistent state
  const [favorites, setFavorites] = React.useState(new Set([3, 4]));
  const [prefs, setPrefs] = React.useState(/*EDITMODE-BEGIN*/{
    "fontSize": "澶?,
    "contrast": false,
    "voice": true,
    "tips": true,
    "simple": false,
    "confirm": true,
    "primaryHue": "warm"
  } /*EDITMODE-END*/);

  const toggleFav = (id) => {
    setFavorites((prev) => {
      const next = new Set(prev);
      next.has(id) ? next.delete(id) : next.add(id);
      return next;
    });
  };

  // 鈹€鈹€ Router 鈹€鈹€
  const [stack, setStack] = React.useState([{ id: 'welcome', params: {} }]);
  const current = stack[stack.length - 1];

  const go = (id, params = {}) => {
    setStack((s) => [...s, { id, params }]);
  };
  const replace = (id, params = {}) => {
    setStack([{ id, params }]);
  };
  const back = () => {
    if (stack.length > 1) setStack((s) => s.slice(0, -1));
  };

  // Bottom-nav-aware "go" 鈥?for tab-style screens, replace stack root
  const navTo = (tab) => {
    const map = { home: 'home', library: 'library', practice: 'warmups', profile: 'profile' };
    replace(map[tab] || tab);
  };

  // Map screen id -> component
  const screens = {
    welcome: <ScreenWelcome go={replace} />,
    login: <ScreenPhoneLogin go={replace} />,
    home: <ScreenHome go={go} streak={7} simpleMode={prefs.simple} />,
    warmups: <ScreenWarmups go={go} />,
    breath: <ScreenBreath go={(id, p) => id === 'warmups' ? back() : go(id, p)} />,
    library: <ScreenLibrary go={go} favorites={favorites} toggleFav={toggleFav} />,
    songDetail: <ScreenSongDetail go={(id, p) => id === 'library' ? back() : go(id, p)} song={current.params.song} favorites={favorites} toggleFav={toggleFav} />,
    sing: <ScreenSing go={(id, p) => id === 'songDetail' ? back() : go(id, p)} song={current.params.song} />,
    feedback: <ScreenFeedback go={(id, p) => id === 'home' ? replace('home') : go(id, p)} song={current.params.song} />,
    profile: <ScreenProfile go={go} favorites={favorites} streak={7} />,
    settings: <ScreenSettings go={(id) => id === 'home' ? back() : go(id)} prefs={prefs} setPrefs={setPrefs} />
  };

  // Which screens show bottom nav
  const bottomNavScreens = new Set(['home', 'library', 'warmups', 'profile']);
  const currentTab = { home: 'home', library: 'library', warmups: 'practice', profile: 'profile' }[current.id];

  // Font-scale wrapper based on prefs
  const fontScale = { 鏍囧噯: 1, 澶? 1.08, 瓒呭ぇ: 1.18 }[prefs.fontSize] || 1.08;
  const contrastFilter = prefs.contrast ? 'contrast(1.1) saturate(1.05)' : 'none';

  return (
    <div style={{
      minHeight: '100vh', background: '#EFE6D4',
      padding: '36px 20px',
      display: 'flex', alignItems: 'flex-start', justifyContent: 'center',
      position: 'relative',
      fontFamily: '"Noto Sans SC", -apple-system, system-ui, sans-serif'
    }}>
      {/* Background decorative texture */}
      <div style={{
        position: 'fixed', inset: 0, pointerEvents: 'none',
        background: 'radial-gradient(ellipse at 20% 0%, #FFD9B055 0%, transparent 50%), radial-gradient(ellipse at 80% 100%, #DDEBF655 0%, transparent 50%)'
      }} />

      {/* Device */}
      <div style={{
        position: 'relative', zIndex: 1,
        fontSize: `${16 * fontScale}px`,
        filter: contrastFilter
      }}>
        <IOSDevice width={402} height={874}>
          <div style={{
            height: '100%', position: 'relative',
            fontSize: `${16 * fontScale}px`
          }}>
            {screens[current.id]}
            {bottomNavScreens.has(current.id) &&
            <YLBottomNav current={currentTab} onChange={navTo} />
            }
          </div>
        </IOSDevice>
      </div>

      {/* Tweaks panel 鈥?appears when activated from toolbar */}
      <AppTweaks prefs={prefs} setPrefs={setPrefs} />
    </div>);

}

